mapper.select:
SELECT A.* FROM ( SELECT CVUR.USER_TYPE ,CVUR.USER_ID ,CVUR.USER_ID AS ORI_USER_ID ,CVUR.USER_NM AS USER_NM ,CVUR.COMPANY_CD ,CUST.CUST_NM AS COMPANY_NM ,CVUR.DEPT_CD ,CVUR.DEPT_NM ,CVUR.PARENT_DEPT_CD ,CVUR.PARENT_DEPT_NM ,CVUR.TEL_NUM AS TEL_NUM ,CVUR.CELL_NUM AS CELL_NUM ,CVUR.EMAIL AS EMAIL ,CVUR.POSITION_NM ,CVUR.DUTY_NM ,CVUR.BLOCK_FLAG ,CVUR.BLOCK_REASON ,(CVUR.REG_DATE, 'yyyyMMdd') AS REG_DATE ,CVUR.SMS_FLAG ,CVUR.MAIL_FLAG FROM STOCCVUR CVUR LEFT OUTER JOIN STOCCUST CUST ON (CUST.GATE_CD = CVUR.GATE_CD AND CUST.CUST_CD = CVUR.COMPANY_CD) LEFT OUTER JOIN STOCOGDP OGDP ON (OGDP.GATE_CD = CVUR.GATE_CD AND OGDP.BUYER_CD = CVUR.COMPANY_CD AND OGDP.DEPT_CD = CVUR.DEPT_CD) WHERE CVUR.GATE_CD = #{ses.gateCd} AND CVUR.DEL_FLAG = '0'
AND CVUR.USER_TYPE = #{USER_TYPE}
AND UPPER(CVUR.USER_ID) LIKE '%' UPPER(#{USER_ID}) '%'
AND UPPER(CVUR.USER_NM) LIKE '%' UPPER(#{USER_NM}) '%'
AND CVUR.COMPANY_CD = #{CUST_CD}
AND UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{CUST_NM}) '%'
AND UPPER(CVUR.DEPT_NM) LIKE '%' UPPER(#{DEPT_NM}) '%'
AND CVUR.REG_DATE >= (#{FROM_DATE}) AND CVUR.REG_DATE <= (#{TO_DATE})
) A ORDER BY A.COMPANY_NM, A.USER_NM

mapper.update:
