    MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , PASSWORD = #{PASSWORD}
    , PW_WRONG_CNT = 0
    , PW_RESET_FLAG = '1'
    , PW_RESET_DATE = SYSDATE
 WHERE GATE_CD = #{ses.gateCd}
   AND USER_ID = #{USER_ID}

UPDATE STOCCVUR SET
    MNG_YN = '0'
 WHERE GATE_CD = #{ses.gateCd}
   AND COMPANY_CD = #{COMPANY_CD}

UPDATE STOCCVUR SET
      DEL_FLAG = '0'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , WORK_TYPE = #{WORK_TYPE}
    , MY_SITE_FLAG = #{MY_SITE_FLAG}
    , WMS_FLAG = #{WMS_FLAG}
    , BUDGET_FLAG = #{BUDGET_FLAG}
    , GR_FLAG = #{GR_FLAG}
    , FINANCIAL_FLAG = #{FINANCIAL_FLAG}
    , BLOCK_FLAG = #{BLOCK_FLAG}
    , BLOCK_REASON = #{BLOCK_REASON}
    , SMS_FLAG = #{SMS_FLAG}
    , MAIL_FLAG = #{MAIL_FLAG}
    , MNG_YN = (#{MNG_YN}, '0')
 WHERE GATE_CD = #{ses.gateCd}
   AND USER_ID = #{ORI_USER_ID}

UPDATE STOCCVUR SET
      DEL_FLAG = '1'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , BLOCK_REASON = #{BLOCK_REASON }
 WHERE GATE_CD = #{ses.gateCd}
   AND USER_ID = #{ORI_USER_ID }

UPDATE STOCCVUR SET
     MOD_DATE = SYSDATE
    ,MOD_USER_ID = #{ses.userId}
    ,PASSWORD = #{PASSWORD} 
    ,PW_WRONG_CNT = 0
    ,PW_RESET_FLAG = '1'
    ,PW_RESET_DATE = SYSDATE
 WHERE GATE_CD = #{ses.gateCd}
   AND USER_ID = #{ORI_USER_ID }

mapper.select:
SELECT COUNT(USER_ID) AS CNT
  FROM STOCUSER
 WHERE GATE_CD = #{ses.gateCd}
   AND USER_ID = #{USER_ID}
   AND PASSWORD = #{PASSWORD}

mapper.insert:
MERGE  STOCCVUR CVUR
USING (SELECT #{ses.gateCd} AS GATE_CD
             ,UPPER(SF_TRIM(#{USER_ID})) AS USER_ID
         ) B
 ON (CVUR.GATE_CD = B.GATE_CD
 AND CVUR.USER_ID = B.USER_ID)
WHEN MATCHED THEN
UPDATE SET
      DEL_FLAG = '0'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , USER_NM = #{USER_NM}
    , DEPT_CD = #{DEPT_CD}
    , DEPT_NM = #{DEPT_NM}
    , PARENT_DEPT_CD = #{PARENT_DEPT_CD}
    , PARENT_DEPT_NM = #{PARENT_DEPT_NM}
    , POSITION_NM = #{POSITION_NM}
    , TEL_NUM = #{TEL_NUM}
    , FAX_NUM = #{FAX_NUM}
    , CELL_NUM = #{CELL_NUM}
    , EMAIL = #{EMAIL}
    , SMS_FLAG = #{SMS_FLAG}
    , MAIL_FLAG = #{MAIL_FLAG}
    , DUTY_NM = #{DUTY_NM}
    , CHIEF_USER_ID = #{CHIEF_USER_ID}
    , ONES_DUTY_NM = #{ONES_DUTY_NM}

    , PASSWORD = #{PASSWORD} 

    , PW_WRONG_CNT = 0
WHEN NOT MATCHED THEN
INSERT (
      GATE_CD
    , USER_ID
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , DEL_FLAG
    , COMPANY_CD
    , USER_TYPE
    , USER_NM
    , PASSWORD
    , DEPT_CD
    , DEPT_NM
    , PARENT_DEPT_CD
    , PARENT_DEPT_NM
    , POSITION_NM
    , TEL_NUM
    , FAX_NUM
    , CELL_NUM
    , EMAIL
    , SMS_FLAG
    , MAIL_FLAG
    , USE_FLAG
    , DUTY_NM
    , CHIEF_USER_ID
    , BLOCK_FLAG
    , PROGRESS_CD
    , CONFIRM_USER_ID
    , CONFIRM_DATE
    , ONES_DUTY_NM
) VALUES (
      #{ses.gateCd}
    , UPPER(SF_TRIM(#{USER_ID}))
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
    , #{COMPANY_CD}
    , #{USER_TYPE}
    , #{USER_NM}
    , #{PASSWORD}
    , #{DEPT_CD}
    , #{DEPT_NM}
    , #{PARENT_DEPT_CD}
    , #{PARENT_DEPT_NM}
    , #{POSITION_NM}
    , #{TEL_NUM}
    , #{FAX_NUM}
    , #{CELL_NUM}
    , #{EMAIL}
    , #{SMS_FLAG}
    , #{MAIL_FLAG}
    , '1'
    , #{DUTY_NM}
    , #{CHIEF_USER_ID}
    , '0'
    , 'E'
    , #{ses.userId}
    , SYSDATE
    , #{ONES_DUTY_NM}
)

