mapper.select:
SELECT
    COUNT(*) AS EXIST_CNT
  FROM STOCBACP CP
 WHERE CP.GATE_CD = #{ses.gateCd}
   AND CP.BUYER_CD = #{BUYER_CD}
   AND CP.CTRL_USER_ID = #{CTRL_USER_ID}
   AND CP.CTRL_CD = #{CTRL_CD}

mapper.insert:
MERGE  STOCBACP BACP
USING (SELECT #{ses.gateCd} AS GATE_CD
             ,#{BUYER_CD} AS BUYER_CD
             ,#{CTRL_CD} AS CTRL_CD
             ,#{CTRL_USER_ID} AS CTRL_USER_ID
         ) B
 ON (BACP.GATE_CD = B.GATE_CD
 AND BACP.BUYER_CD = B.BUYER_CD
 AND BACP.CTRL_CD = B.CTRL_CD
 AND BACP.CTRL_USER_ID = B.CTRL_USER_ID)
WHEN MATCHED THEN
UPDATE SET
      DEL_FLAG = '0'
    , USE_FLAG = #{USE_FLAG}
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHEN NOT MATCHED THEN
INSERT (
      GATE_CD
    , BUYER_CD
    , CTRL_CD
    , CTRL_USER_ID
    , REG_DATE
    , REG_USER_ID
    , MOD_DATE
    , MOD_USER_ID
    , DEL_FLAG
    , USE_FLAG
) VALUES (
      #{ses.gateCd}
    , #{BUYER_CD}
    , #{CTRL_CD}
    , #{CTRL_USER_ID}
    , SYSDATE
    , #{ses.userId}
    , SYSDATE
    , #{ses.userId}
    , '0'
    , #{USE_FLAG}
)

